options(stringsAsFactors=FALSE)
# Load data
df <- read.csv('/app/bn_sample_10k.csv', check.names=FALSE)
nodes <- colnames(df)
# define possible directed edges excluding incoming to U
all_edges <- list()
for (f in nodes) {
  for (t in nodes) {
    if (f != t && t != 'U') all_edges[[length(all_edges)+1]] <- c(f,t)
  }
}
edge_mat <- do.call(rbind, all_edges)
colnames(edge_mat) <- c('from','to')

is_acyclic <- function(edges, nodes) {
  # edges: matrix 2 cols from,to
  incoming <- setNames(as.list(rep(0, length(nodes))), nodes)
  outgoing <- setNames(vector('list', length(nodes)), nodes)
  for (nd in nodes) outgoing[[nd]] <- character(0)
  if (!is.null(edges) && nrow(edges)>0) {
    for (i in seq_len(nrow(edges))) {
      f <- edges[i,1]; t <- edges[i,2]
      outgoing[[f]] <- c(outgoing[[f]], t)
      incoming[[t]] <- incoming[[t]] + 1
    }
  }
  q <- nodes[sapply(incoming, function(x) x==0)]
  visited <- 0
  while (length(q)>0) {
    v <- q[1]; q <- q[-1]
    visited <- visited + 1
    for (w in outgoing[[v]]) {
      incoming[[w]] <- incoming[[w]] - 1
      if (incoming[[w]] == 0) q <- c(q, w)
    }
  }
  visited == length(nodes)
}

node_score <- function(y, X) {
  n <- length(y)
  if (is.null(X) || ncol(X)==0) {
    mu <- mean(y)
    rss <- sum((y-mu)^2)
    p <- 1
  } else {
    Xd <- cbind(1, as.matrix(X))
    fit <- lm.fit(x=Xd, y=y)
    rss <- sum(fit$residuals^2)
    p <- ncol(Xd)
  }
  if (rss <= 0) rss <- 1e-12
  sigma2 <- rss / n
  loglik <- -n/2 * (log(2*pi*sigma2) + 1)
  k <- p + 1 # regression params + variance
  bic <- loglik - 0.5*k*log(n)
  bic
}

dag_score <- function(edges) {
  total <- 0
  for (nd in nodes) {
    pa <- character(0)
    if (!is.null(edges) && nrow(edges)>0) pa <- edges[edges[,2]==nd,1]
    X <- if (length(pa)==0) NULL else df[, pa, drop=FALSE]
    total <- total + node_score(df[[nd]], X)
  }
  total
}

